program
	.command("place-order")
	.summary("place-order --broker <broker> --symbol <symbol> --side <side:buy|sell> --qty <qty:number> [--order-type <order-type:market|limit|stop|stop_limit|trailing_stop>] [--raw <json>]")
	.description("Place a trading order on any connected broker. Supports market, limit, stop, stop-limit, and trailing stop orders across Alpaca, IBKR, Oanda, TradersPost (Schwab/Robinhood/Tastytrade), and QuantConnect.")
	.usage("--broker <broker> --symbol <symbol> --side <side:buy|sell> --qty <qty:number> [--order-type <order-type:market|limit|stop|stop_limit|trailing_stop>] [--raw <json>]")
	.option('--raw <json>', 'Provide raw JSON arguments to the tool, bypassing flag parsing.')

	.requiredOption("--broker <broker>", "Broker name: alpaca, ibkr, oanda, traderspost, quantconnect")
	.requiredOption("--symbol <symbol>", "Ticker symbol (e.g. AAPL, EUR_USD, ES)")
	.requiredOption("--side <side:buy|sell>", "Set side. (choices: buy, sell; example: buy)")
	.requiredOption("--qty <qty:number>", "Order quantity (example: 1)", (value) => parseFloat(value))
	.option("--order-type <order-type:market|limit|stop|stop_limit|trailing_stop>", "Set order_type. (choices: market, limit, stop, stop_limit, trailing_stop; default: market; example: market)")
	.option("--limit-price <limit-price:number>", "Limit price (for limit/stop-limit orders) (example: 1)", (value) => parseFloat(value))
	.option("--stop-price <stop-price:number>", "Stop price (for stop/stop-limit orders) (example: 1)", (value) => parseFloat(value))
	.option("--trail-pct <trail-pct:number>", "Trailing stop percentage (example: 1)", (value) => parseFloat(value))
	.option("--time-in-force <time-in-force>", "Set time_in_force. (default: day; example: day)")
	
	.alias("place_order")	.action(async (cmdOpts) => {
		const globalOptions = program.opts();
		const runtime = await ensureRuntime();
		const serverName = embeddedName;
		const proxy = createServerProxy(runtime, serverName, {
			initialSchemas: embeddedSchemas,
		});
		try {
			const args = cmdOpts.raw ? JSON.parse(cmdOpts.raw) : ({} as Record<string, unknown>);
			if (cmdOpts.broker !== undefined) args.broker = cmdOpts.broker;
		if (cmdOpts.symbol !== undefined) args.symbol = cmdOpts.symbol;
		if (cmdOpts.side !== undefined) args.side = cmdOpts.side;
		if (cmdOpts.qty !== undefined) args.qty = cmdOpts.qty;
		if (cmdOpts.orderType !== undefined) args.order_type = cmdOpts.orderType;
		if (cmdOpts.limitPrice !== undefined) args.limit_price = cmdOpts.limitPrice;
		if (cmdOpts.stopPrice !== undefined) args.stop_price = cmdOpts.stopPrice;
		if (cmdOpts.trailPct !== undefined) args.trail_pct = cmdOpts.trailPct;
		if (cmdOpts.timeInForce !== undefined) args.time_in_force = cmdOpts.timeInForce;
			const call = (proxy.placeOrder as any)(args);
			const result = await invokeWithTimeout(call, globalOptions.timeout || 30000);
			printResult(result, globalOptions.output ?? 'text');
		} finally {
			await runtime.close(serverName).catch(() => {});
		}
	})
	.addHelpText('after', () => '\nExample:\n  ' + "mcporter call algochains.place_order(broker: \"value\", symbol: \"value\", sid, ...)")
	.addHelpText('afterAll', () => '\n' + "// optional (4): limit_price, stop_price, trail_pct, time_in_force" + '\n');

